"""
Operational status snapshot helpers for the admin control plane.
"""

from __future__ import annotations

from datetime import datetime, timedelta, timezone
from time import monotonic
from typing import Any

from operational_config import get_public_operational_config


def _default_scheduler_runtime_provider() -> dict[str, int | bool]:
    return {"running": False, "scheduled_jobs": 0}


_scheduler_runtime_provider = _default_scheduler_runtime_provider


def _now() -> datetime:
    return datetime.now(timezone.utc)


def _sort_key(value: Any) -> datetime:
    if isinstance(value, datetime):
        return value
    return datetime.fromtimestamp(0, tz=timezone.utc)


def _base_service(status: str, *, last_checked=None, error=None, details=None, consumption=None) -> dict:
    return {
        "status": status,
        "last_checked": last_checked or _now(),
        "error": error,
        "details": details or {},
        "consumption": consumption or {},
    }


async def collect_backend_status(db) -> dict:
    if db is None:
        return _base_service("error", error="Database not connected")

    now = _now()
    active_sessions = await db.refresh_tokens.count_documents({
        "revoked": False,
        "expires_at": {"$gt": now},
    })
    pending_recon = await db.recon_scheduled.count_documents({"status": "pending"})
    return _base_service(
        "healthy",
        details={"api_prefix": "/api", "database_connected": True},
        consumption={
            "active_sessions": active_sessions,
            "pending_recon_jobs": pending_recon,
        },
    )


async def collect_mongodb_status(db) -> dict:
    if db is None:
        return _base_service("error", error="Database not connected")

    latency_ms = None
    if hasattr(db, "command"):
        started = monotonic()
        await db.command("ping")
        latency_ms = max(int((monotonic() - started) * 1000), 0)

    return _base_service(
        "healthy",
        details={"ping": "ok"},
        consumption={
            "latency_ms": latency_ms,
            "users": await db.users.count_documents({}),
            "scans": await db.scans.count_documents({}),
        },
    )


def set_scheduler_runtime_provider(provider) -> None:
    global _scheduler_runtime_provider
    _scheduler_runtime_provider = provider


def _get_scheduler_runtime_state() -> dict:
    try:
        runtime = _scheduler_runtime_provider() or {}
    except Exception as exc:
        return {
            "running": False,
            "scheduled_jobs": 0,
            "error": str(exc),
        }

    return {
        "running": bool(runtime.get("running", False)),
        "scheduled_jobs": int(runtime.get("scheduled_jobs", 0) or 0),
        "error": runtime.get("error"),
    }


async def collect_scheduler_status(_db) -> dict:
    runtime = _get_scheduler_runtime_state()
    return _base_service(
        "healthy" if runtime["running"] else "degraded",
        details={"running": runtime["running"]},
        consumption={"scheduled_jobs": runtime["scheduled_jobs"]},
        error=None if runtime["running"] else runtime.get("error") or "Scheduler is not running",
    )


async def collect_worker_status(db) -> dict:
    if db is None:
        return _base_service("error", error="Database not connected")

    doc = await db.system_status.find_one({"module": "worker"}) or {}
    last_run = doc.get("last_run")
    if not last_run:
        return _base_service(
            "degraded",
            error="Worker has not reported status yet",
            details={"reported": False},
        )

    stale_after = _now() - timedelta(hours=36)
    status = "healthy" if last_run >= stale_after else "degraded"
    return _base_service(
        status,
        last_checked=last_run,
        error=doc.get("error") if status != "healthy" else None,
        details={
            "reported": True,
            "reported_status": str(doc.get("status", "unknown")).lower(),
        },
        consumption={"altered_targets": int(doc.get("altered_targets", 0) or 0)},
    )


async def collect_mailer_status(db) -> dict:
    public_config = await get_public_operational_config(db)
    smtp = public_config["smtp"]
    configured = bool(smtp["host"]["value"])
    return _base_service(
        "healthy" if configured else "degraded",
        error=None if configured else "SMTP is not configured",
        details={
            "configured": configured,
            "host": smtp["host"]["value"],
            "port": smtp["port"]["value"],
            "from_email": smtp["from"]["value"],
            "tls": smtp["tls"]["value"],
        },
        consumption={},
    )


SERVICE_COLLECTORS = {
    "backend": collect_backend_status,
    "mongodb": collect_mongodb_status,
    "scheduler": collect_scheduler_status,
    "worker": collect_worker_status,
    "mailer": collect_mailer_status,
}


async def _persist_operational_snapshot(db, snapshot: dict) -> None:
    if db is None:
        return

    checked_at = snapshot.get("checked_at") or _now()
    await db.operational_status_history.insert_one({
        "recorded_at": checked_at,
        "summary": snapshot.get("summary", {}),
        "services": snapshot.get("services", {}),
    })


async def get_operational_status_history(db, *, limit: int = 24) -> list[dict]:
    if db is None:
        return []

    raw_items = await db.operational_status_history.find({}, {"_id": 0}).to_list(length=max(limit * 3, limit))
    items = sorted(raw_items, key=lambda item: _sort_key(item.get("recorded_at")))
    if not items:
        snapshot = await get_operational_status_snapshot(db, persist=True)
        items = [{
            "recorded_at": snapshot.get("checked_at"),
            "summary": snapshot.get("summary", {}),
            "services": snapshot.get("services", {}),
        }]
    return items[-limit:]


def _matches_operational_event(action: str) -> bool:
    if not action:
        return False
    return (
        action == "service_restart"
        or action.startswith("threat_source_")
        or action.startswith("smtp_test_")
        or action.startswith("extension_")
    )


def _infer_service_name(entry: dict) -> str:
    detail = str(entry.get("detail") or "")
    target = str(entry.get("target") or "")
    action = str(entry.get("action") or "")

    if "service=" in detail:
        for chunk in detail.split(","):
            chunk = chunk.strip()
            if chunk.startswith("service="):
                return chunk.split("=", 1)[1] or "runtime"
    if action.startswith("threat_source_"):
        return target or "threat_ingestion"
    if action.startswith("smtp_test_"):
        return "mailer"
    if action.startswith("extension_"):
        return target or "extensions"
    return target or "runtime"


def _infer_category(action: str) -> str:
    if action == "service_restart":
        return "runtime"
    if action.startswith("threat_source_"):
        return "ingestion"
    if action.startswith("smtp_test_"):
        return "mailer"
    if action.startswith("extension_"):
        return "extensions"
    return "runtime"


async def get_operational_event_stream(db, *, page: int = 1, page_size: int = 20) -> dict:
    if db is None:
        return {"items": [], "total": 0, "page": page, "pages": 1}

    raw_items = await db.audit_log.find({}, {"_id": 0}).to_list(length=250)
    filtered = [
        {
            **item,
            "service": _infer_service_name(item),
            "category": _infer_category(str(item.get("action") or "")),
        }
        for item in raw_items
        if _matches_operational_event(str(item.get("action") or ""))
    ]
    filtered.sort(key=lambda item: _sort_key(item.get("timestamp")), reverse=True)
    total = len(filtered)
    pages = max(1, (total + page_size - 1) // page_size)
    start = (page - 1) * page_size
    end = start + page_size
    return {
        "items": filtered[start:end],
        "total": total,
        "page": page,
        "pages": pages,
    }


async def get_operational_status_snapshot(db, *, persist: bool = True) -> dict:
    services: dict[str, dict] = {}
    summary = {"healthy": 0, "degraded": 0, "error": 0}

    for name, collector in SERVICE_COLLECTORS.items():
        try:
            service = await collector(db)
        except Exception as exc:
            service = _base_service("error", error=str(exc))
        services[name] = service
        summary[service["status"]] = summary.get(service["status"], 0) + 1

    snapshot = {
        "checked_at": _now(),
        "summary": summary,
        "services": services,
    }
    if persist:
        await _persist_operational_snapshot(db, snapshot)
    return snapshot

"""
Recon correlator — builds Attack Surface and extracts Risk Indicators
from a finished recon job's results dict.

Used by:
  - GET /recon/{job_id}  (adds attack_surface + risk_indicators to export payload)
  - ReconPage.jsx frontend (mirrors logic for inline display)
"""


def correlate(results: dict) -> dict:
    """
    Build structured Attack Surface from module results.

    Args:
        results: dict of {module_name: {status, data, duration_ms, from_cache}}

    Returns:
        {
            "exposed_services": [...],
            "infrastructure": {...},
            "certificates": {...},
            "passive": {...},
            "subdomains": [...],
        }
    """

    def _data(module: str) -> dict | None:
        entry = results.get(module)
        if not entry or entry.get("status") == "error":
            return None
        d = entry.get("data")
        if not d or d.get("error") or d.get("skipped"):
            return None
        return d

    dns = _data("dns")
    whois = _data("whois")
    ssl = _data("ssl")
    web = _data("web")
    ports = _data("ports")
    passive = _data("passive")
    subdomains = _data("subdomains")

    # ── Exposed Services ──────────────────────────────────────────────
    exposed_services = []
    if ports and ports.get("ports"):
        for p in ports["ports"]:
            svc = {
                "port": p.get("port"),
                "protocol": p.get("protocol", "tcp"),
                "service": p.get("service", ""),
                "product": p.get("product", ""),
                "version": p.get("version", ""),
            }
            exposed_services.append(svc)

    if web and web.get("status_code"):
        # Add HTTP/HTTPS as a synthetic service if not already from nmap
        http_ports = {s["port"] for s in exposed_services}
        final_url = web.get("final_url", "")
        port_hint = 443 if final_url.startswith("https") else 80
        if port_hint not in http_ports:
            exposed_services.append({
                "port": port_hint,
                "protocol": "tcp",
                "service": "https" if port_hint == 443 else "http",
                "product": web.get("server", ""),
                "version": "",
            })

    # ── Infrastructure ────────────────────────────────────────────────
    infrastructure = {}
    if dns:
        infrastructure["a_records"] = dns.get("A", [])
        infrastructure["aaaa_records"] = dns.get("AAAA", [])
        infrastructure["mx_records"] = dns.get("MX", [])
        infrastructure["ns_records"] = dns.get("NS", [])
        infrastructure["txt_records"] = dns.get("TXT", [])
    if whois:
        infrastructure["registrar"] = whois.get("registrar")
        infrastructure["registrant_country"] = whois.get("registrant_country")
        infrastructure["creation_date"] = whois.get("creation_date")
        infrastructure["expiration_date"] = whois.get("expiration_date")
        infrastructure["name_servers"] = whois.get("name_servers", [])
        infrastructure["org"] = whois.get("org")
    if web:
        infrastructure["technologies"] = web.get("technologies", [])
        infrastructure["server"] = web.get("server")
        infrastructure["final_url"] = web.get("final_url")
        infrastructure["title"] = web.get("title")

    # ── Certificates ──────────────────────────────────────────────────
    certificates = {}
    if ssl:
        certificates = {
            "subject_cn": ssl.get("subject_cn"),
            "issuer_cn": ssl.get("issuer_cn"),
            "not_after": ssl.get("not_after"),
            "days_until_expiry": ssl.get("days_until_expiry"),
            "is_expired": ssl.get("is_expired", False),
            "is_self_signed": ssl.get("is_self_signed", False),
            "protocol": ssl.get("protocol"),
            "sans": ssl.get("sans", []),
        }

    # ── Passive ───────────────────────────────────────────────────────
    passive_data = {}
    if passive:
        passive_data = {
            "emails": passive.get("emails", []),
            "ips": passive.get("ips", []),
        }

    subs = []
    if subdomains:
        subs = subdomains.get("subdomains", [])
    # Also merge passive subdomains
    if passive:
        for s in passive.get("subdomains", []):
            if s not in subs:
                subs.append(s)

    return {
        "exposed_services": exposed_services,
        "infrastructure": infrastructure,
        "certificates": certificates,
        "passive": passive_data,
        "subdomains": subs,
    }


def extract_risks(results: dict) -> list[dict]:
    """
    Extract risk indicators from module results.

    Returns list of {severity, category, message} dicts.
    """
    risks = []

    def _data(module: str) -> dict | None:
        entry = results.get(module)
        if not entry or entry.get("status") == "error":
            return None
        d = entry.get("data")
        if not d or d.get("error") or d.get("skipped"):
            return None
        return d

    ssl = _data("ssl")
    web = _data("web")
    ports = _data("ports")
    passive = _data("passive")
    subdomains = _data("subdomains")

    # SSL risks
    if ssl:
        if ssl.get("is_expired"):
            risks.append({"severity": "critical", "category": "ssl", "message": "SSL certificate is expired"})
        elif ssl.get("days_until_expiry") is not None and ssl["days_until_expiry"] < 30:
            risks.append({"severity": "high", "category": "ssl",
                          "message": f"SSL certificate expires in {ssl['days_until_expiry']} days"})
        if ssl.get("is_self_signed"):
            risks.append({"severity": "medium", "category": "ssl", "message": "SSL certificate is self-signed"})
        protocol = ssl.get("protocol", "")
        if protocol in ("TLSv1", "TLSv1.0", "TLSv1.1", "SSLv3"):
            risks.append({"severity": "high", "category": "ssl",
                          "message": f"Deprecated TLS protocol in use: {protocol}"})

    # Web / security headers
    if web:
        sec = web.get("security_headers", {})
        missing = [h for h, present in sec.items() if not present]
        if "Strict-Transport-Security" in missing:
            risks.append({"severity": "medium", "category": "web", "message": "Missing HSTS header"})
        if "Content-Security-Policy" in missing:
            risks.append({"severity": "medium", "category": "web", "message": "Missing Content-Security-Policy header"})
        if "X-Frame-Options" in missing:
            risks.append({"severity": "low", "category": "web", "message": "Missing X-Frame-Options header"})
        if web.get("x_powered_by"):
            risks.append({"severity": "low", "category": "web",
                          "message": f"Server technology exposed: {web['x_powered_by']}"})

    # Non-standard open ports
    if ports and ports.get("ports"):
        standard = {21, 22, 23, 25, 53, 80, 110, 143, 443, 587, 993, 995, 3306, 5432, 6379, 8080, 8443}
        for p in ports["ports"]:
            if p.get("port") and p["port"] not in standard:
                risks.append({
                    "severity": "low",
                    "category": "ports",
                    "message": (
                        f"Non-standard port open: {p['port']}/"
                        f"{p.get('protocol', 'tcp')} ({p.get('service', '')})"
                    ),
                })

    # Passive harvested emails
    if passive and passive.get("emails"):
        count = len(passive["emails"])
        risks.append({"severity": "info", "category": "passive",
                      "message": f"{count} email address(es) found — potential phishing targets"})

    # Large subdomain footprint
    sub_count = len(subdomains.get("subdomains", [])) if subdomains else 0
    if passive:
        sub_count += len(passive.get("subdomains", []))
    if sub_count > 20:
        risks.append({"severity": "info", "category": "subdomains",
                      "message": f"Large attack surface: {sub_count} subdomains discovered"})

    return risks

"""
Premium hunting router.

Provides the initial authenticated surface for premium hunting providers.
"""

from __future__ import annotations

from datetime import datetime, timezone
from typing import Any
from uuid import uuid4

from fastapi import APIRouter, Depends, HTTPException, Request
from pydantic import BaseModel, Field, field_validator

from audit import log_action
from auth import get_current_user
from hunting_runtime import (
    SHERLOCK_SUPPORTED_ARTIFACT_TYPES,
    build_hunting_runtime_catalog,
    build_sherlock_provider_descriptor,
    build_sherlock_query,
    normalize_sherlock_results,
    resolve_hunting_provider_runtime,
    run_sherlock_query,
)
from db import db_manager
from limiters import limiter

router = APIRouter(prefix="/hunting", tags=["hunting"])


def _get_hunting_providers(exec_runner=None) -> list[dict[str, Any]]:
    providers = [build_sherlock_provider_descriptor()]
    return [
        {
            **provider,
            "runtimeStatus": resolve_hunting_provider_runtime(provider, exec_runner=exec_runner),
        }
        for provider in providers
    ]


class HuntingSearchRequest(BaseModel):
    artifact_type: str
    query: str
    provider_keys: list[str] | None = None

    @field_validator("artifact_type", "query")
    @classmethod
    def _strip_text(cls, value: str) -> str:
        return value.strip()


class SavedHuntingSearchRequest(BaseModel):
    name: str
    artifact_type: str
    query: str
    provider_keys: list[str] = Field(default_factory=list)

    @field_validator("name", "artifact_type", "query")
    @classmethod
    def _strip_saved_text(cls, value: str) -> str:
        return value.strip()


class HuntingCaseNoteRequest(BaseModel):
    search_id: str
    note: str

    @field_validator("search_id", "note")
    @classmethod
    def _strip_note_text(cls, value: str) -> str:
        return value.strip()


@router.get("/providers")
async def list_hunting_providers(request: Request, current_user: dict = Depends(get_current_user)):
    _ = current_user
    exec_runner = getattr(request.app.state, "hunting_exec_runner", None)
    return {
        "items": _get_hunting_providers(exec_runner=exec_runner),
        "runtime": build_hunting_runtime_catalog(exec_runner=exec_runner),
    }


@router.get("/saved-searches")
async def list_saved_hunting_searches(current_user: dict = Depends(get_current_user)):
    db = db_manager.db
    if db is None:
        return {"items": []}

    docs = await db.hunting_saved_searches.find(
        {"analyst": current_user["username"]},
        {"_id": 0},
    ).sort("created_at", -1).limit(50).to_list(length=50)
    return {"items": docs}


@router.post("/saved-searches", status_code=201)
async def create_saved_hunting_search(
    body: SavedHuntingSearchRequest,
    current_user: dict = Depends(get_current_user),
):
    db = db_manager.db
    if db is None:
        raise HTTPException(status_code=503, detail="database_unavailable")

    doc = {
        "_id": uuid4().hex,
        "analyst": current_user["username"],
        "name": body.name,
        "artifact_type": body.artifact_type,
        "query": body.query,
        "provider_keys": body.provider_keys,
        "created_at": datetime.now(timezone.utc),
        "last_used_at": None,
        "use_count": 0,
    }
    await db.hunting_saved_searches.insert_one(doc)
    return {"item": doc}


@router.delete("/saved-searches/{saved_search_id}")
async def delete_saved_hunting_search(
    saved_search_id: str,
    current_user: dict = Depends(get_current_user),
):
    db = db_manager.db
    if db is None:
        raise HTTPException(status_code=503, detail="database_unavailable")

    result = await db.hunting_saved_searches.delete_one(
        {"_id": saved_search_id, "analyst": current_user["username"]},
    )
    if result.deleted_count == 0:
        raise HTTPException(status_code=404, detail="saved_hunting_search_not_found")
    return {"ok": True}


@router.get("/recent-searches")
async def list_recent_hunting_searches(current_user: dict = Depends(get_current_user)):
    db = db_manager.db
    if db is None:
        return {"items": []}

    docs = await db.hunting_results.find(
        {"analyst": current_user["username"]},
        {"_id": 0},
    ).sort("timestamp", -1).limit(250).to_list(length=250)

    grouped: dict[str, dict[str, Any]] = {}
    for doc in docs:
        search_id = doc.get("search_id")
        if not search_id:
            continue
        bucket = grouped.get(search_id)
        if bucket is None:
            bucket = {
                "search_id": search_id,
                "artifact_type": doc.get("artifact_type"),
                "query": doc.get("query"),
                "timestamp": doc.get("search_timestamp") or doc.get("timestamp"),
                "providers": set(),
                "result_count": 0,
            }
            grouped[search_id] = bucket
        bucket["providers"].add(doc.get("provider_key"))
        bucket["result_count"] += 1

    items = sorted(
        [
            {
                **value,
                "providers": sorted([provider for provider in value["providers"] if provider]),
            }
            for value in grouped.values()
        ],
        key=lambda item: item.get("timestamp") or datetime.now(timezone.utc),
        reverse=True,
    )[:20]
    return {"items": items}


@router.get("/case-notes")
async def list_hunting_case_notes(
    search_id: str,
    current_user: dict = Depends(get_current_user),
):
    db = db_manager.db
    if db is None:
        return {"items": []}

    docs = await db.hunting_case_notes.find(
        {"analyst": current_user["username"], "search_id": search_id},
        {"_id": 0},
    ).sort("created_at", -1).limit(50).to_list(length=50)
    return {"items": docs}


@router.post("/case-notes", status_code=201)
async def create_hunting_case_note(
    body: HuntingCaseNoteRequest,
    current_user: dict = Depends(get_current_user),
):
    db = db_manager.db
    if db is None:
        raise HTTPException(status_code=503, detail="database_unavailable")

    note = {
        "_id": uuid4().hex,
        "analyst": current_user["username"],
        "search_id": body.search_id,
        "note": body.note,
        "created_at": datetime.now(timezone.utc),
    }
    await db.hunting_case_notes.insert_one(note)
    return {"item": note}


@router.post("/search")
@limiter.limit("5/minute", error_message="Too many premium hunting searches. Try again later.")
async def run_hunting_search(
    body: HuntingSearchRequest,
    request: Request,
    current_user: dict = Depends(get_current_user),
):
    if not body.query:
        raise HTTPException(status_code=400, detail="query_required")
    if not body.artifact_type:
        raise HTTPException(status_code=400, detail="artifact_type_required")

    exec_runner = getattr(request.app.state, "hunting_exec_runner", None)
    providers = _get_hunting_providers(exec_runner=exec_runner)
    requested_keys = body.provider_keys or [provider["key"] for provider in providers]
    requested = [provider for provider in providers if provider["key"] in requested_keys]
    unknown_keys = sorted(set(requested_keys) - {provider["key"] for provider in providers})
    if unknown_keys:
        raise HTTPException(
            status_code=400,
            detail=f"unknown_hunting_provider:{','.join(unknown_keys)}",
        )

    provider_results: list[dict[str, Any]] = []
    total_results = 0
    db = db_manager.db
    search_id = uuid4().hex
    request_ip = request.client.host if request.client else ""

    for provider in requested:
        query_payload = build_sherlock_query(
            artifact_type=body.artifact_type,
            query=body.query,
            analyst=current_user["username"],
        )

        if body.artifact_type not in SHERLOCK_SUPPORTED_ARTIFACT_TYPES:
            provider_results.append(
                {
                    "provider": provider,
                    "query": query_payload,
                    "status": "unsupported",
                    "error": f"unsupported_artifact_type:{body.artifact_type}",
                    "results": [],
                }
            )
            continue

        runtime_status = provider.get("runtimeStatus") or resolve_hunting_provider_runtime(provider, exec_runner=exec_runner)
        if not runtime_status.get("ready"):
            provider_results.append(
                {
                    "provider": provider,
                    "query": query_payload,
                    "status": "error",
                    "error": runtime_status.get("blocker") or "provider_runtime_missing",
                    "results": [],
                }
            )
            continue

        try:
            raw_output = await run_sherlock_query(query_payload, exec_runner=exec_runner)
            results = normalize_sherlock_results(query_payload, raw_output)
            if db is not None:
                for result in results:
                    result["_id"] = uuid4().hex
                    result["search_id"] = search_id
                    result["search_timestamp"] = datetime.now(timezone.utc)
                    result["data_boundary"] = "premium_hunting"
                    result["storage_scope"] = "user"
                    result["analyst"] = current_user["username"]
                    await db.hunting_results.insert_one(result)
            provider_results.append(
                {
                    "provider": provider,
                    "query": query_payload,
                    "status": "ok",
                    "error": None,
                    "results": results,
                }
            )
            total_results += len(results)
        except FileNotFoundError:
            provider_results.append(
                {
                    "provider": provider,
                    "query": query_payload,
                    "status": "error",
                    "error": "provider_runtime_missing",
                    "results": [],
                }
            )
        except RuntimeError as exc:
            provider_results.append(
                {
                    "provider": provider,
                    "query": query_payload,
                    "status": "error",
                    "error": str(exc),
                    "results": [],
                }
            )
        except ValueError as exc:
            provider_results.append(
                {
                    "provider": provider,
                    "query": query_payload,
                    "status": "error",
                    "error": str(exc),
                    "results": [],
                }
            )

    if db is not None:
        matching_saved = await db.hunting_saved_searches.find_one(
            {
                "analyst": current_user["username"],
                "artifact_type": body.artifact_type,
                "query": body.query,
            }
        )
        if matching_saved:
            await db.hunting_saved_searches.update_one(
                {"_id": matching_saved["_id"]},
                {"$set": {"last_used_at": datetime.now(timezone.utc), "provider_keys": requested_keys},
                 "$inc": {"use_count": 1}},
            )
        has_success = any(item["status"] == "ok" for item in provider_results)
        has_failure = any(item["status"] == "error" for item in provider_results)
        await log_action(
            db,
            user=current_user["username"],
            action="premium_hunting_search",
            target=body.query,
            ip=request_ip,
            result="failure" if has_failure and not has_success else "success",
            detail=f"{body.artifact_type}:{total_results}:{','.join(item['status'] for item in provider_results)}",
        )

    return {
        "query": {
            "artifact_type": body.artifact_type,
            "query": body.query,
        },
        "search_id": search_id,
        "items": provider_results,
        "total_results": total_results,
    }

