@router.patch("/me/third-party-keys")
async def update_third_party_keys(
    request: Request,
    body: ThirdPartyKeysUpdate,
    current_user: dict = Depends(get_current_user),
):
    """Save or update encrypted third-party API keys for the current user."""
    db = db_manager.db
    if db is None:
        raise HTTPException(status_code=500, detail="Database not connected")

    invalid = set(body.keys.keys()) - ALLOWED_SERVICES
    if invalid:
        raise HTTPException(status_code=400, detail=f"Invalid services: {', '.join(invalid)}")

    user_doc = await db.users.find_one({"username": current_user["username"]})
    existing = user_doc.get("third_party_keys", {}) if user_doc else {}
    changed_services: list[str] = []
    configured_services: list[str] = []
    removed_services: list[str] = []

    for svc, value in body.keys.items():
        if value and value.strip():
            existing[svc] = encrypt_secret(value.strip())
            changed_services.append(svc)
            configured_services.append(svc)
        elif svc in existing:
            del existing[svc]
            changed_services.append(svc)
            removed_services.append(svc)

    await db.users.update_one(
        {"username": current_user["username"]},
        {"$set": {"third_party_keys": existing}}
    )
    ip = request.client.host if request.client else ""
    detail_parts = []
    if configured_services:
        detail_parts.append(f"configured={','.join(sorted(configured_services))}")
    if removed_services:
        detail_parts.append(f"removed={','.join(sorted(removed_services))}")
    detail_parts.append(f"changed={len(changed_services)}")
    await log_action(
        db,
        user=current_user["username"],
        action="third_party_keys_updated",
        target=current_user["username"],
        ip=ip,
        result="success",
        detail="; ".join(detail_parts),
    )
    return {"status": "success", "message": "Third-party keys updated"}


@router.delete("/{username}")
async def delete_user(request: Request, username: str, current_user: dict = Depends(require_role(["admin"]))):
    db = db_manager.db
    if db is None:
        raise HTTPException(status_code=500, detail="Database not connected")

    if current_user["username"] == username:
        raise HTTPException(status_code=400, detail="You cannot delete yourself")

    revoked_count = await revoke_user_refresh_tokens(db, username)
    result = await db.users.delete_one({"username": username})
    if result.deleted_count == 0:
        raise HTTPException(status_code=404, detail="User not found")

    ip = request.client.host if request.client else ""
    await log_action(db, user=current_user["username"], action="user_deleted",
                     target=username, ip=ip, result="success",
                     detail=f"revoked_sessions={revoked_count}")
    return {"status": "success", "message": f"User {username} deleted successfully"}


@router.put("/{username}")
async def update_user(
    request: Request,
    username: str,
    user_update: UserUpdate,
    current_user: dict = Depends(require_role(["admin"])),
):
    db = db_manager.db
    if db is None:
        raise HTTPException(status_code=500, detail="Database not connected")

    existing = await db.users.find_one({"username": username})
    if not existing:
        raise HTTPException(status_code=404, detail="User not found")

    update_data = {}
    revoke_sessions = False
    if user_update.name is not None:
        update_data["name"] = user_update.name
    if user_update.role is not None:
        if user_update.role not in VALID_ROLES:
            raise HTTPException(status_code=400, detail="Invalid role specified")
        if (current_user["username"] == username
                and existing.get("role") == "admin"
                and user_update.role != "admin"):
            raise HTTPException(status_code=400, detail="You cannot demote your own admin account")
        update_data["role"] = user_update.role
        revoke_sessions = revoke_sessions or is_sensitive_role_downgrade(existing.get("role"), user_update.role)
    if user_update.password is not None:
        policy = await get_password_policy(db)
        errors = validate_password(user_update.password, policy)
        if errors:
            raise HTTPException(status_code=400, detail=errors[0])
        new_hash = get_password_hash(user_update.password)
        update_data["password_hash"] = new_hash
        update_data["password_changed_at"] = datetime.now(timezone.utc)
        update_data["force_password_reset"] = False
        history = existing.get("password_history", [])
        history_count = policy.get("history_count", 5)
        update_data["password_history"] = (history + [new_hash])[-history_count:]
        revoke_sessions = True
    if user_update.is_active is not None:
        if current_user["username"] == username and user_update.is_active is False:
            raise HTTPException(status_code=400, detail="You cannot suspend your own account")
        update_data["is_active"] = user_update.is_active
        if user_update.is_active is False:
            revoke_sessions = True
            reason = (user_update.suspension_reason or "").strip()
            if reason:
                update_data["suspension_reason"] = reason[:500]
            else:
                update_data["suspension_reason"] = None
            update_data["suspended_at"] = datetime.now(timezone.utc)
            update_data["suspended_by"] = current_user["username"]
        else:
            update_data["suspension_reason"] = None
            update_data["suspended_at"] = None
            update_data["suspended_by"] = None
    if user_update.force_password_reset is not None:
        update_data["force_password_reset"] = user_update.force_password_reset
        if user_update.force_password_reset is True:
            revoke_sessions = True
    if user_update.email is not None:
        normalized_email = normalize_email(user_update.email)
        if normalized_email and not is_valid_email_format(normalized_email):
            raise HTTPException(status_code=400, detail="Invalid email format")
        if await email_in_use(db, normalized_email, exclude_username=username):
            raise HTTPException(status_code=400, detail="Email already in use")
        update_data["email"] = normalized_email
        update_data["normalized_email"] = normalized_email
    if user_update.allowed_ips is not None:
        # Validate each entry as IP, CIDR, or IPv6
        validated = []
        for entry in user_update.allowed_ips:
            entry = entry.strip()
            if not entry:
                continue
            try:
                ipaddress.ip_network(entry, strict=False)
                validated.append(entry)
            except ValueError:
                try:
                    ipaddress.ip_address(entry)
                    validated.append(entry)
                except ValueError:
                    raise HTTPException(status_code=400, detail=f"Invalid IP/CIDR: {entry}")
        update_data["allowed_ips"] = validated

    if not update_data:
        return {"status": "success", "message": "No fields to update"}

    await db.users.update_one({"username": username}, {"$set": update_data})
    revoked_count = await revoke_user_refresh_tokens(db, username) if revoke_sessions else 0

    ip = request.client.host if request.client else ""
    # Emit granular audit events
    if "role" in update_data:
        await log_action(db, user=current_user["username"], action="role_changed",
                         target=username, ip=ip, result="success",
                         detail=f"new_role={update_data['role']}; revoked_sessions={revoked_count}")
    if update_data.get("force_password_reset") is True:
        await log_action(db, user=current_user["username"], action="password_reset_forced",
                         target=username, ip=ip, result="success",
                         detail=f"revoked_sessions={revoked_count}")
    if "is_active" in update_data:
        action_name = "user_reactivated" if update_data["is_active"] else "user_suspended"
        detail = f"revoked_sessions={revoked_count}"
        if update_data["is_active"] is False and update_data.get("suspension_reason"):
            detail += f"; reason={update_data['suspension_reason']}"
        await log_action(db, user=current_user["username"], action=action_name,
                         target=username, ip=ip, result="success",
                         detail=detail)
    else:
        await log_action(db, user=current_user["username"], action="user_updated",
                         target=username, ip=ip, result="success",
                         detail=f"revoked_sessions={revoked_count}")

    return {"status": "success", "message": f"User {username} updated successfully"}

from datetime import datetime, timezone

from fastapi import APIRouter, HTTPException, Depends, Query
from pydantic import BaseModel, field_validator

from db import db_manager
from auth import get_current_user
from validators import validate_target, ValidationError
from logging_config import get_logger
from watchlist_runtime import (
    evaluate_watchlist_target,
    normalize_watchlist_notification_route,
    persist_watchlist_scan,
)

logger = get_logger("WatchlistRouter")

router = APIRouter(prefix="/watchlist", tags=["watchlist"])


# ── SMTP status (used by frontend to enable/disable email notifications) ─────

@router.get("/smtp-status")
async def smtp_status(current_user: dict = Depends(get_current_user)):
    from mailer import is_smtp_configured
    return {"smtp_configured": await is_smtp_configured()}

WATCHLIST_LIMIT = 50


class WatchlistAdd(BaseModel):
    target: str
    notify_on_change: bool = True
    notification_route: str = "email"

    @field_validator("notification_route")
    @classmethod
    def _normalize_route(cls, value: str) -> str:
        return normalize_watchlist_notification_route(value)


class WatchlistBulkRequest(BaseModel):
    item_ids: list[str]
    action: str
    notification_route: str | None = None

    @field_validator("action")
    @classmethod
    def _normalize_action(cls, value: str) -> str:
        return str(value or "").strip().lower()

    @field_validator("notification_route")
    @classmethod
    def _optional_route(cls, value: str | None) -> str | None:
        if value is None:
            return None
        return normalize_watchlist_notification_route(value)


def _serialize_value(value):
    if hasattr(value, "isoformat"):
        return value.isoformat()
    return value


def _serialize_watchlist_item(doc: dict) -> dict:
    return {
        "id": str(doc["_id"]),
        "target": doc["target"],
        "target_type": doc.get("target_type", ""),
        "notify_on_change": doc.get("notify_on_change", True),
        "notification_route": doc.get("notification_route", "email"),
        "last_verdict": doc.get("last_verdict"),
        "last_scan_at": _serialize_value(doc.get("last_scan_at")),
        "created_at": _serialize_value(doc.get("created_at")),
    }


# ── GET / — list user's watchlist ─────────────────────────────────────────────

@router.get("/")
async def list_watchlist(
    current_user: dict = Depends(get_current_user),
):
    if db_manager.db is None:
        raise HTTPException(status_code=503, detail="Database unavailable.")

    cursor = db_manager.db.watchlist.find(
        {"user": current_user["username"]},
    ).sort("created_at", -1)

    items = []
    async for doc in cursor:
        items.append(_serialize_watchlist_item(doc))

    return {"items": items, "total": len(items), "limit": WATCHLIST_LIMIT}


# ── POST / — add target to watchlist ─────────────────────────────────────────

@router.post("/", status_code=201)
async def add_to_watchlist(
    body: WatchlistAdd,
    current_user: dict = Depends(get_current_user),
):
    if db_manager.db is None:
        raise HTTPException(status_code=503, detail="Database unavailable.")

    # Validate target
    try:
        v = validate_target(body.target.strip())
    except ValidationError as e:
        raise HTTPException(status_code=400, detail=str(e))

    username = current_user["username"]

    # Check limit
    count = await db_manager.db.watchlist.count_documents({"user": username})
    if count >= WATCHLIST_LIMIT:
        raise HTTPException(
            status_code=422,
            detail=f"Watchlist limit reached ({WATCHLIST_LIMIT}).",
        )

    # Check duplicate
    existing = await db_manager.db.watchlist.find_one({
        "user": username, "target": v.sanitized,
    })
    if existing:
        raise HTTPException(status_code=409, detail="Target already in watchlist.")

    doc = {
        "user": username,
        "target": v.sanitized,
        "target_type": v.target_type,
        "notify_on_change": body.notify_on_change,
        "notification_route": body.notification_route,
        "last_verdict": None,
        "last_scan_at": None,
        "created_at": datetime.now(timezone.utc),
    }

    result = await db_manager.db.watchlist.insert_one(doc)
    doc["id"] = str(result.inserted_id)

    return {
        "id": doc["id"],
        "target": doc["target"],
        "target_type": doc["target_type"],
        "notify_on_change": doc["notify_on_change"],
        "notification_route": doc["notification_route"],
    }


# ── PATCH /{id} — toggle notify ──────────────────────────────────────────────

@router.patch("/{item_id}")
async def update_watchlist_item(
    item_id: str,
    body: dict,
    current_user: dict = Depends(get_current_user),
):
    if db_manager.db is None:
        raise HTTPException(status_code=503, detail="Database unavailable.")

    from bson import ObjectId

    try:
        oid = ObjectId(item_id)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid ID.")

    doc = await db_manager.db.watchlist.find_one({"_id": oid})
    if not doc or doc["user"] != current_user["username"]:
        raise HTTPException(status_code=404, detail="Item not found.")

    update = {}
    if "notify_on_change" in body:
        update["notify_on_change"] = bool(body["notify_on_change"])
    if "notification_route" in body:
        try:
            update["notification_route"] = normalize_watchlist_notification_route(body["notification_route"])
        except ValueError as exc:
            raise HTTPException(status_code=400, detail=str(exc))

    if update:
        await db_manager.db.watchlist.update_one({"_id": oid}, {"$set": update})

    return {"ok": True}


@router.post("/bulk")
async def bulk_watchlist_action(
    body: WatchlistBulkRequest,
    current_user: dict = Depends(get_current_user),
):
    if db_manager.db is None:
        raise HTTPException(status_code=503, detail="Database unavailable.")

    from bson import ObjectId

    normalized_ids = []
    for item_id in body.item_ids:
        try:
            normalized_ids.append(ObjectId(item_id))
        except Exception:
            raise HTTPException(status_code=400, detail="Invalid ID.")

    owned_items = []
    for oid in normalized_ids:
        doc = await db_manager.db.watchlist.find_one({"_id": oid})
        if doc and doc["user"] == current_user["username"]:
            owned_items.append(doc)

    if not owned_items:
        return {"updated": 0}

    updated = 0
    for doc in owned_items:
        if body.action == "enable_notifications":
            await db_manager.db.watchlist.update_one(
                {"_id": doc["_id"]},
                {"$set": {"notify_on_change": True}},
            )
            updated += 1
        elif body.action == "disable_notifications":
            await db_manager.db.watchlist.update_one(
                {"_id": doc["_id"]},
                {"$set": {"notify_on_change": False}},
            )
            updated += 1
        elif body.action == "set_route":
            if not body.notification_route:
                raise HTTPException(status_code=400, detail="notification_route_required")
            await db_manager.db.watchlist.update_one(
                {"_id": doc["_id"]},
                {"$set": {"notification_route": body.notification_route}},
            )
            updated += 1
        elif body.action == "delete":
            result = await db_manager.db.watchlist.delete_one(
                {"_id": doc["_id"], "user": current_user["username"]},
            )
            updated += int(result.deleted_count > 0)
        else:
            raise HTTPException(status_code=400, detail=f"unsupported_bulk_action:{body.action}")

    return {"updated": updated}


@router.post("/{item_id}/scan")
async def scan_watchlist_item(
    item_id: str,
    current_user: dict = Depends(get_current_user),
):
    if db_manager.db is None:
        raise HTTPException(status_code=503, detail="Database unavailable.")

    from bson import ObjectId
    from clients.api_client_async import AsyncThreatIntelClient

    try:
        oid = ObjectId(item_id)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid ID.")

    doc = await db_manager.db.watchlist.find_one({"_id": oid})
    if not doc or doc["user"] != current_user["username"]:
        raise HTTPException(status_code=404, detail="Item not found.")

    try:
        async with AsyncThreatIntelClient() as client:
            runtime = await evaluate_watchlist_target(
                client,
                doc["target"],
                doc.get("target_type", "ip"),
            )
    except ValueError as exc:
        raise HTTPException(status_code=424, detail=str(exc))

    persisted = await persist_watchlist_scan(
        db_manager.db,
        doc,
        verdict=runtime["verdict"],
    )
    refreshed = await db_manager.db.watchlist.find_one({"_id": oid}) or doc
    return {
        "item": _serialize_watchlist_item(refreshed),
        "changed": persisted["changed"],
        "previous_verdict": persisted["previous_verdict"],
        "verdict": persisted["verdict"],
        "total_sources": runtime["total_sources"],
    }


@router.get("/{item_id}/history")
async def read_watchlist_item_history(
    item_id: str,
    limit: int = Query(12, ge=3, le=60),
    current_user: dict = Depends(get_current_user),
):
    if db_manager.db is None:
        raise HTTPException(status_code=503, detail="Database unavailable.")

    from bson import ObjectId

    try:
        oid = ObjectId(item_id)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid ID.")

    doc = await db_manager.db.watchlist.find_one({"_id": oid})
    if not doc or doc["user"] != current_user["username"]:
        raise HTTPException(status_code=404, detail="Item not found.")

    history = await db_manager.db.watchlist_history.find(
        {"user": current_user["username"], "watchlist_item_id": item_id},
        {"_id": 0},
    ).sort("scanned_at", -1).limit(limit).to_list(length=limit)

    serialized = [
        {
            **entry,
            "scanned_at": _serialize_value(entry.get("scanned_at")),
        }
        for entry in history
    ]
    return {"items": serialized, "total": len(serialized)}


