        self.inserted_id = inserted_id


class FakeCursor:
    """Minimal async cursor shim that supports sort/skip/limit chaining."""

    def __init__(self, data):
        self._data = list(data)

    def sort(self, *args, **kwargs):
        return self

    def limit(self, n):
        self._data = self._data[:n]
        return self

    def skip(self, n):
        self._data = self._data[n:]
        return self

    async def to_list(self, length=None):
        if length is not None:
            return self._data[:length]
        return self._data


class FakeCollection:
    """Minimal async collection shim for tests."""

    def __init__(self, data=None):
        self._data = list(data or [])

    async def create_index(self, *args, **kwargs):
        return kwargs.get("name")

    async def find_one(self, query, *args, **kwargs):
        for doc in self._data:
            if all(doc.get(k) == v for k, v in query.items() if not isinstance(v, dict)):
                return doc
        return None

    def find(self, query=None, projection=None):
        if not query:
            return FakeCursor(list(self._data))
        results = []
        for doc in self._data:
            match = True
            for k, v in query.items():
                if isinstance(v, dict):
                    doc_val = doc.get(k)
                    if doc_val is None:
                        match = False
                        break
                    if "$gte" in v and doc_val < v["$gte"]:
                        match = False
                        break
                    if "$gt" in v and doc_val <= v["$gt"]:
                        match = False
                        break
                    if "$lte" in v and doc_val > v["$lte"]:
                        match = False
                        break
                    if "$lt" in v and doc_val >= v["$lt"]:
                        match = False
                        break
                else:
                    if doc.get(k) != v:
                        match = False
                        break
            if match:
                results.append(doc)
        return FakeCursor(results)

    def aggregate(self, pipeline):
        return FakeCursor([])

    async def insert_one(self, doc):
        if "_id" not in doc:
            from bson import ObjectId
            doc["_id"] = ObjectId()
        self._data.append(doc)
        return _InsertResult(doc["_id"])

    async def replace_one(self, query, replacement, upsert=False):
        for i, doc in enumerate(self._data):
            if all(doc.get(k) == v for k, v in query.items()):
                self._data[i] = replacement
                return
        if upsert:
            self._data.append(replacement)

    async def update_one(self, query, update, upsert=False):
        for doc in self._data:
            if all(doc.get(k) == v for k, v in query.items()):
                for op, fields in update.items():
                    if op == "$set":
                        doc.update(fields)
                    elif op == "$inc":
                        for key, value in fields.items():
                            doc[key] = doc.get(key, 0) + value
                return
        if upsert:
            new_doc = dict(query)
            for op, fields in update.items():
                if op == "$set":
                    new_doc.update(fields)
                elif op == "$inc":
                    for key, value in fields.items():
                        new_doc[key] = new_doc.get(key, 0) + value
            self._data.append(new_doc)

    async def delete_one(self, query):
        for i, doc in enumerate(self._data):
            if all(doc.get(k) == v for k, v in query.items()):
                self._data.pop(i)
                return _DeleteResult(deleted_count=1)
        return _DeleteResult(deleted_count=0)

    async def count_documents(self, query):
        count = 0
        for doc in self._data:
            match = True
            for k, v in query.items():
                if isinstance(v, dict):
                    doc_val = doc.get(k)
                    if doc_val is None:
                        match = False
                        break
                    if "$gte" in v and doc_val < v["$gte"]:
                        match = False
                        break
                    if "$gt" in v and doc_val <= v["$gt"]:
                        match = False
                        break
                    if "$lte" in v and doc_val > v["$lte"]:
                        match = False
                        break
                    if "$lt" in v and doc_val >= v["$lt"]:
                        match = False
                        break
                else:
                    if doc.get(k) != v:
                        match = False
                        break
            if match:
                count += 1
        return count

    async def distinct(self, field, query=None):
        values = []
        for doc in self.find(query)._data:
            value = doc.get(field)
            if value not in values:
                values.append(value)
        return values


